#include <iostream>
#include <string>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int K;
    string N;
    cin >> K >> N;

    int oddSum = 0, evenSum = 0;
    for (size_t i = 0; i < N.size(); i++) {
        int digit = N[i] - '0';
        if ((i + 1) % 2 == 1) { // odd position (1-indexed from most significant)
            oddSum += digit;
        } else {
            evenSum += digit;
        }
    }

    int diff = oddSum - evenSum;
    if (diff % K == 0) {
        cout << "YES\n";
    } else {
        cout << "NO\n";
    }

    return 0;
}
